import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.ChXBHUFc.js";const s="/triki/img/axes.jpg",m=JSON.parse('{"title":"IMU streaming","description":"","frontmatter":{},"headers":[],"relativePath":"guide/imu-streaming.md","filePath":"guide/imu-streaming.md","lastUpdated":1782666423000}'),i={name:"guide/imu-streaming.md"};function n(c,e,d,l,h,g){return a(),o("div",null,[...e[0]||(e[0]=[r(`<h1 id="imu-streaming" tabindex="-1">IMU streaming <a class="header-anchor" href="#imu-streaming" aria-label="Permalink to &quot;IMU streaming&quot;">​</a></h1><p>The Triki streams raw accelerometer + gyroscope over BLE once you send a multi-byte start command on RX. <strong>Verified live here.</strong></p><h2 id="start-the-stream" tabindex="-1">Start the stream <a class="header-anchor" href="#start-the-stream" aria-label="Permalink to &quot;Start the stream&quot;">​</a></h2><p>Write to RX <code>…0002</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>20 10 00 D0 07 68 00 03</span></span></code></pre></div><p>(<code>68 00</code> = 104 → ~104 Hz sample rate.)</p><h2 id="stream-format" tabindex="-1">Stream format <a class="header-anchor" href="#stream-format" aria-label="Permalink to &quot;Stream format&quot;">​</a></h2><p>The device then pushes 14-byte frames on TX <code>…0003</code>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>offset  0    2     4     6      8      10     12</span></span>
<span class="line"><span>        22 00 gyroX gyroY gyroZ accelX accelY accelZ</span></span>
<span class="line"><span>header ─┘     └──────────────── 6 × int16 LE ──────┘</span></span></code></pre></div><p>Bytes 0–1 are the <code>22 00</code> header; the six axes follow as signed int16, little-endian at offsets 2 / 4 / 6 (gyro) and 8 / 10 / 12 (accel). Scales:</p><ul><li><strong>gyro / 14.286</strong> → deg/s — LSM6DSL ±2000 dps (70 mdps/LSB). The older <code>131.0</code> was an MPU-6050 ±250 dps value carried over from notes; it under-rotated ~9×.</li><li><strong>accel / 2048.0</strong> → g — LSM6DSL ±16 g (flat token reads +2048 = 1 g).</li></ul><p>Frames arrive in bursts at ~104 Hz (the default; the rate is selectable — see <a href="./ble-protocol#sample-rate-odr">Sample rate</a>).</p><h3 id="startup-behaviour" tabindex="-1">Startup behaviour <a class="header-anchor" href="#startup-behaviour" aria-label="Permalink to &quot;Startup behaviour&quot;">​</a></h3><ul><li>The <strong>first ~20 frames after start are noise</strong> — discard them before trusting the data (to be verified).</li><li>For a clean gravity/zero baseline, let the token sit <strong>flat and still</strong> for a moment before sending the start command.</li><li>There is no stop opcode: the stream ends when you disconnect.</li></ul><h2 id="axis-orientation" tabindex="-1">Axis orientation <a class="header-anchor" href="#axis-orientation" aria-label="Permalink to &quot;Axis orientation&quot;">​</a></h2><p>The IMU axes were mapped empirically — holding the token still in each face-up / edge-up pose and reading which accelerometer axis settles at ±1 g. Reference frame: look at the <strong>PCB face</strong> (the green board with the <strong>Ż</strong> logo) held upright; <strong>+Z</strong> points out of the PCB face, toward you.</p><p><img src="`+s+'" alt="Triki IMU axes — looking at the PCB face"></p><table tabindex="0"><thead><tr><th>Axis</th><th>Points toward (PCB face up, Ż upright)</th></tr></thead><tbody><tr><td><strong>+Z</strong></td><td>out of the PCB face (Ż side)</td></tr><tr><td><strong>−Z</strong></td><td>out of the cap face (metal crown / &quot;T&quot; logo)</td></tr><tr><td><strong>−Y</strong></td><td>top of the Ż (12 o&#39;clock)</td></tr><tr><td><strong>+Y</strong></td><td>bottom of the Ż (6 o&#39;clock)</td></tr><tr><td><strong>−X</strong></td><td>right of the Ż (3 o&#39;clock)</td></tr><tr><td><strong>+X</strong></td><td>left of the Ż (9 o&#39;clock)</td></tr></tbody></table><p>The accelerometer axes form a <strong>right-handed</strong> triad (X × Y = +Z), matching the LSM6DSL convention.</p><p>Measured (token still, one axis up at a time): PCB face up → Z ≈ +1.0 g; cap face up → Z ≈ −1.0 g; top of Ż up → Y ≈ −1.0 g; right of Ż up → X ≈ −1.0 g; left of Ż up → X ≈ +1.0 g. Per-axis magnitudes vary by a few percent (uncalibrated MEMS offset/scale).</p><h3 id="what-the-accelerometer-vector-means" tabindex="-1">What the accelerometer vector means <a class="header-anchor" href="#what-the-accelerometer-vector-means" aria-label="Permalink to &quot;What the accelerometer vector means&quot;">​</a></h3><p>The accelerometer measures <strong>specific force</strong> — the support/reaction force on the sensor — <strong>not</strong> gravity directly. At rest it reads the reaction that holds the token out of free fall, so the vector points <strong>up, away from Earth</strong>, with magnitude ≈ 1 g: the axis facing the sky reads <strong>+1 g</strong>. The direction <em>toward</em> Earth is therefore <strong>−accel</strong> while the token is still. In free fall it would read ≈ 0. During motion, linear acceleration adds to the gravity component — which is why orientation is recovered with a fusion filter (Madgwick) rather than by trusting raw accel as &quot;down&quot;.</p><h2 id="verification" tabindex="-1">Verification <a class="header-anchor" href="#verification" aria-label="Permalink to &quot;Verification&quot;">​</a></h2><p>Under shaking, gyro swings ±10000+, and the accel axis aligned with gravity reads ≈ +2048 (= 1 g) — decode confirmed at ~104 Hz. Reader: <code>tools/ble_imu_stream.py</code> (see <a href="./tooling">Tooling</a>).</p><p>This is sufficient to use the token as a <strong>motion controller</strong> — recover orientation via gyro + accel fusion (e.g. Madgwick AHRS).</p><blockquote><p>Note: the single-byte opcodes (<code>0x05</code> / <code>0x07</code> / <code>0x09</code> / …) are a separate diagnostic/management interface — raw IMU is NOT there; it only comes from the start-stream command above.</p></blockquote>',26)])])}const u=t(i,[["render",n]]);export{m as __pageData,u as default};
